class ModelRegistry:
    """Manages trained models and their metadata."""

    def __init__(self):
        self.current_model = None
        self.model_info = {}
        self.class_names = []
        self._load_latest_model()

    def _load_latest_model(self):
        model_path = MODEL_DIR / "latest_model"
        info_path = METADATA_DIR / "model_info.json"
        if model_path.exists() and info_path.exists():
            try:
                self.current_model = keras.models.load_model(str(model_path))
                with open(info_path, 'r') as f:
                    self.model_info = json.load(f)
                self.class_names = self.model_info.get('class_names', [])
                logger.info("Loaded existing model with classes: %s", self.class_names)
            except Exception as e:
                logger.warning("Could not load existing model: %s", e)
                self.current_model = None

    def save_model(self, model, class_names, metrics, contribution_ids):
        self.current_model = model
        self.class_names = class_names
        model_path = MODEL_DIR / "latest_model"
        model.save(str(model_path))

        version = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
        versioned_path = MODEL_DIR / f"model_{version}"
        model.save(str(versioned_path))

        self.model_info = {
            'version': version,
            'class_names': class_names,
            'num_classes': len(class_names),
            'metrics': metrics,
            'trained_at': datetime.utcnow().isoformat(),
            'contribution_ids': contribution_ids,
            'img_size': list(IMG_SIZE)
        }
        with open(METADATA_DIR / "model_info.json", 'w') as f:
            json.dump(self.model_info, f, indent=2)

        logger.info("Model saved: version=%s, classes=%d", version, len(class_names))


model_registry = ModelRegistry()


def allowed_file(filename, allowed_extensions):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in allowed_extensions


def log_contribution(contribution_id, contributor, description, num_samples, labels):
    contributions = []
    if CONTRIBUTION_LOG.exists():
        with open(CONTRIBUTION_LOG, 'r') as f:
            contributions = json.load(f)

    contributions.append({
        'id': contribution_id,
        'contributor': contributor,
        'description': description,
        'num_samples': num_samples,
        'labels': labels,
        'timestamp': datetime.utcnow().isoformat(),
        'status': 'accepted'
    })

    with open(CONTRIBUTION_LOG, 'w') as f:
        json.dump(contributions, f, indent=2)


def validate_and_sanitize_csv(filepath):
    """Validate CSV structure and sanitize data."""
    try:
        df = pd.read_csv(filepath)
    except Exception as e:
        return None, f"Failed to parse CSV: {e}"

    if len(df) == 0:
        return None, "CSV file is empty"

    if len(df) > 100000:
        return None, "CSV exceeds maximum of 100,000 rows"

    required_columns_option1 = {'image_path', 'label'}
    required_columns_option2 = {'pixel_data', 'label'}
    required_columns_option3 = {'image_url', 'label'}

    cols = set(df.columns.str.lower().str.strip())
    df.columns = df.columns.str.lower().str.strip()

    if not (required_columns_option1.issubset(cols) or
            required_columns_option2.issubset(cols) or
            required_columns_option3.issubset(cols)):
        return None, (
            "CSV must contain columns: (image_path, label) or "
            "(pixel_data, label) or (image_url, label)"
        )

    df['label'] = df['label'].astype(str).str.strip()
    df = df[df['label'].str.len() > 0]

    unique_labels = df['label'].unique()
    if len(unique_labels) < 2:
        return None, "At least 2 distinct labels are required"
    if len(unique_labels) > MAX_CLASSES:
        return None, f"Too many classes ({len(unique_labels)}). Maximum is {MAX_CLASSES}"

    return df, None


def load_image(image_source, source_type='path'):
    """Load and preprocess a single image."""
    try:
        if source_type == 'path':
            img = Image.open(image_source).convert('RGB')
        elif source_type == 'pixels':
            pixels = np.array(json.loads(image_source), dtype=np.float32)
            if pixels.ndim == 1:
                side = int(np.sqrt(len(pixels) / 3))
                if side * side * 3 == len(pixels):
                    pixels = pixels.reshape((side, side, 3))
                else:
                    side = int(np.sqrt(len(pixels)))
                    pixels = pixels.reshape((side, side))
                    pixels = np.stack([pixels] * 3, axis=-1)
            elif pixels.ndim == 2:
                pixels = np.stack([pixels] * 3, axis=-1)

            if pixels.max() > 1.0:
                pixels = pixels / 255.0
            pixels = (pixels * 255).astype(np.uint8)
            img = Image.fromarray(pixels, 'RGB')
        else:
            return None

        img = img.resize(IMG_SIZE, Image.LANCZOS)
        img_array = np.array(img, dtype=np.float32) / 255.0
        return img_array

    except Exception as e:
        logger.warning("Failed to load image: %s", e)
        return None


def prepare_dataset_from_contributions():
    """Load all accepted training data from contributions."""
    all_images = []
    all_labels = []
    contribution_ids = []

    if not CONTRIBUTION_LOG.exists():
        return None, None, [], []

    with open(CONTRIBUTION_LOG, 'r') as f:
        contributions = json.load(f)

    for contrib in contributions:
        if contrib.get('status') != 'accepted':
            continue

        cid = contrib['id']
        contribution_ids.append(cid)
        csv_path = TRAINING_DATA_DIR / f"{cid}.csv"
        images_path = IMAGES_DIR / cid

        if not csv_path.exists():
            continue

        df = pd.read_csv(csv_path)
        df.columns = df.columns.str.lower().str.strip()

        for _, row in df.iterrows():
            label = str(row['label']).strip()
            img = None

            if 'image_path' in df.columns:
                img_file = images_path / str(row['image_path'])
                if img_file.exists():
                    img = load_image(str(img_file), 'path')
            elif 'pixel_data' in df.columns:
                img = load_image(str(row['pixel_data']), 'pixels')

            if img is not None:
                all_images.append(img)
                all_labels.append(label)

    if len(all_images) == 0:
        return None, None, [], contribution_ids

    unique_labels = sorted(set(all_labels))
    label_to_idx = {l: i for i, l in enumerate(unique_labels)}
    encoded_labels = [label_to_idx[l] for l in all_labels]

    X = np.array(all_images)
    y = np.array(encoded_labels)

    return X, y, unique_labels, contribution_ids


def build_image_classification_model(num_classes, input_shape=(64, 64, 3)):
    """Build a CNN model for image classification."""
    model = keras.Sequential([
        layers.Input(shape=input_shape),

        layers.Conv2D(32, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        layers.Conv2D(64, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        layers.Conv2D(128, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        layers.Conv2D(256, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.GlobalAveragePooling2D(),
        layers.Dropout(0.5),

        layers.Dense(256, activation='relu'),
        layers.BatchNormalization(),
        layers.Dropout(0.5),
        layers.Dense(num_classes, activation='softmax')
    ])

    model.compile(
        optimizer=keras.optimizers.Adam(learning_rate=0.001),
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )

    return model


def train_model(X, y, class_names, contribution_ids, epochs=20, batch_size=32):
    """Train the model on the provided data."""
    num_classes = len(class_names)
    num_samples = len(X)

    indices = np.random.permutation(num_samples)
    split = int(0.8 * num_samples)
    train_idx, val_idx = indices[:split], indices[split:]

    X_train, y_train = X[train_idx], y[train_idx]
    X_val, y_val = X[val_idx], y[val_idx]

    if len(X_val) == 0:
        X_val, y_val = X_train, y_train

    model = build_image_classification_model(num_classes, input_shape=X.shape[1:])

    datagen = keras.preprocessing.image.ImageDataGenerator(
        rotation_range=15,
        width_shift_range=0.1,
        height_shift_range=0.1,
        horizontal_flip=True,
        zoom_range=0.1
    )
    datagen.fit(X_train)

    callbacks = [
        keras.callbacks.EarlyStopping(
            monitor='val_loss', patience=5, restore_best_weights=True
        ),
        keras.callbacks.ReduceLROnPlateau(
            monitor='val_loss', factor=0.5, patience=3, min_lr=1e-6
        )
    ]

    history = model.fit(
        datagen.flow(X_train, y_train, batch_size=batch_size),
        epochs=epochs,
        validation_data=(X_val, y_val),
        callbacks=callbacks,
        verbose=1
    )

    val_loss, val_acc = model.evaluate(X_val, y_val, verbose=0)
    metrics = {
        'val_loss': float(val_loss),
        'val_accuracy': float(val_acc),
        'train_samples': int(len(X_train)),
        'val_samples': int(len(X_val)),
        'epochs_trained': len(history.history['loss']),
        'final_train_loss': float(history.history['loss'][-1]),
        'final_train_accuracy': float(history.history['accuracy'][-1])
    }

    model_registry.save_model(model, class_names, metrics, contribution_ids)

    return metrics


