@app.route('/api/contribute', methods=['POST'])
def contribute_training_data():
    """
    Upload training data (CSV + optional images).
    CSV must have columns: (image_path, label) or (pixel_data, label)
    """
    if 'csv_file' not in request.files:
        return jsonify({'error': 'No CSV file provided. Use field name "csv_file"'}), 400

    csv_file = request.files['csv_file']
    if not csv_file or not allowed_file(csv_file.filename, ALLOWED_DATA_EXTENSIONS):
        return jsonify({'error': 'Invalid file. Must be a .csv file'}), 400

    contributor = request.form.get('contributor', 'anonymous')
    description = request.form.get('description', '')

    contribution_id = str(uuid.uuid4())[:12]

    csv_save_path = TRAINING_DATA_DIR / f"{contribution_id}.csv"
    csv_file.save(str(csv_save_path))

    df, error = validate_and_sanitize_csv(str(csv_save_path))
    if error:
        os.remove(str(csv_save_path))
        return jsonify({'error': error}), 400

    images_dir = IMAGES_DIR / contribution_id
    images_dir.mkdir(parents=True, exist_ok=True)

    image_files = request.files.getlist('images')
    saved_images = 0
    for img_file in image_files:
        if img_file and allowed_file(img_file.filename, ALLOWED_IMAGE_EXTENSIONS):
            filename = secure_filename(img_file.filename)
            img_file.save(str(images_dir / filename))
            saved_images += 1

    df.to_csv(str(csv_save_path), index=False)

    unique_labels = df['label'].unique().tolist()
    log_contribution(
        contribution_id, contributor, description,
        len(df), unique_labels
    )

    return jsonify({
        'message': 'Training data accepted',
        'contribution_id': contribution_id,
        'num_samples': len(df),
        'num_images_uploaded': saved_images,
        'labels': unique_labels,
        'contributor': contributor
    }), 201


@app.route('/api/contribute/image', methods=['POST'])
def contribute_single_image():
    """Contribute a single labeled image for training."""
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400
    if 'label' not in request.form:
        return jsonify({'error': 'No label provided'}), 400

    image_file = request.files['image']
    label = request.form['label'].strip()
    contributor = request.form.get('contributor', 'anonymous')

    if not image_file or not allowed_file(image_file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({'error': 'Invalid image file'}), 400

    if not label:
        return jsonify({'error': 'Label cannot be empty'}), 400

    contribution_id = str(uuid.uuid4())[:12]

    images_dir = IMAGES_DIR / contribution_id
    images_dir.mkdir(parents=True, exist_ok=True)
    filename = secure_filename(image_file.filename)
    image_file.save(str(images_dir / filename))

    csv_data = pd.DataFrame([{'image_path': filename, 'label': label}])
    csv_path = TRAINING_DATA_DIR / f"{contribution_id}.csv"
    csv_data.to_csv(str(csv_path), index=False)

    log_contribution(contribution_id, contributor, 'single image', 1, [label])

    return jsonify({
        'message': 'Image contribution accepted',
        'contribution_id': contribution_id,
        'label': label
    }), 201


@app.route('/api/train', methods=['POST'])
def trigger_training():
    """Trigger model training using all contributed data."""
    epochs = request.json.get('epochs', 20) if request.is_json else 20
    batch_size = request.json.get('batch_size', 32) if request.is_json else 32

    epochs = min(max(int(epochs), 1), 100)
    batch_size = min(max(int(batch_size), 4), 128)

    logger.info("Starting training pipeline...")

    X, y, class_names, contribution_ids = prepare_dataset_from_contributions()

    if X is None or len(X) == 0:
        return jsonify({
            'error': 'No valid training data available. Please contribute data first.'
        }), 400

    if len(X) < 10:
        return jsonify({
            'error': f'Insufficient training data ({len(X)} samples). Need at least 10.'
        }), 400

    logger.info("Training with %d samples, %d classes", len(X), len(class_names))

    try:
        metrics = train_model(X, y, class_names, contribution_ids, epochs, batch_size)
    except Exception as e:
        logger.error("Training failed: %s", e)
        return jsonify({'error': f'Training failed: {str(e)}'}), 500

    return jsonify({
        'message': 'Model trained successfully',
        'metrics': metrics,
        'class_names': class_names,
        'num_contributions': len(contribution_ids)
    })


@app.route('/api/predict', methods=['POST'])
def predict():
    """Make predictions on uploaded images."""
    if model_registry.current_model is None:
        return jsonify({'error': 'No model available. Train a model first.'}), 400

    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    image_file = request.files['image']
    if not image_file or not allowed_file(image_file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({'error': 'Invalid image file'}), 400

    try:
        img = Image.open(image_file.stream).convert('RGB')
        img = img.resize(IMG_SIZE, Image.LANCZOS)
        img_array = np.array(img, dtype=np.float32) / 255.0
        img_array = np.expand_dims(img_array, axis=0)

        predictions = model_registry.current_model.predict(img_array, verbose=0)
        predicted_idx = int(np.argmax(predictions[0]))
        confidence = float(predictions[0][predicted_idx])

        results = {
            'predicted_label': model_registry.class_names[predicted_idx],
            'confidence': confidence,
            'all_predictions': {
                model_registry.class_names[i]: float(predictions[0][i])
                for i in range(len(model_registry.class_names))
            }
        }

        return jsonify(results)

    except Exception as e:
        logger.error("Prediction failed: %s", e)
        return jsonify({'error': f'Prediction failed: {str(e)}'}), 500


@app.route('/api/predict/batch', methods=['POST'])
def predict_batch():
    """Make predictions on multiple uploaded images."""
    if model_registry.current_model is None:
        return jsonify({'error': 'No model available. Train a model first.'}), 400

    image_files = request.files.getlist('images')
    if not image_files:
        return jsonify({'error': 'No image files provided'}), 400

    results = []
    for image_file in image_files:
        if not allowed_file(image_file.filename, ALLOWED_IMAGE_EXTENSIONS):
            results.append({
                'filename': image_file.filename,
                'error': 'Invalid file type'
            })
            continue

        try:
            img = Image.open(image_file.stream).convert('RGB')
            img = img.resize(IMG_SIZE, Image.LANCZOS)
            img_array = np.array(img, dtype=np.float32) / 255.0
            img_array = np.expand_dims(img_array, axis=0)

            predictions = model_registry.current_model.predict(img_array, verbose=0)
            predicted_idx = int(np.argmax(predictions[0]))

            results.append({
                'filename': image_file.filename,
                'predicted_label': model_registry.class_names[predicted_idx],
                'confidence': float(predictions[0][predicted_idx])
            })
        except Exception as e:
            results.append({
                'filename': image_file.filename,
                'error': str(e)
            })

    return jsonify({'predictions': results})


