@app.route('/api/data/stats', methods=['GET'])
def data_statistics():
    """Get statistics about the training data."""
    X, y, class_names, contribution_ids = prepare_dataset_from_contributions()

    if X is None:
        return jsonify({
            'total_samples': 0,
            'num_classes': 0,
            'classes': {},
            'num_contributions': 0
        })

    class_counts = {}
    for label_idx in y:
        label = class_names[label_idx]
        class_counts[label] = class_counts.get(label, 0) + 1

    return jsonify({
        'total_samples': len(X),
        'num_classes': len(class_names),
        'classes': class_counts,
        'num_contributions': len(contribution_ids),
        'image_shape': list(X.shape[1:])
    })


@app.route('/api/retrain', methods=['POST'])
def retrain_with_new_data():
    """
    Combined endpoint: upload new data and immediately retrain.
    """
    if 'csv_file' not in request.files:
        return jsonify({'error': 'No CSV file provided'}), 400

    csv_file = request.files['csv_file']
    contributor = request.form.get('contributor', 'anonymous')
    description = request.form.get('description', 'retrain contribution')
    epochs = int(request.form.get('epochs', 20))

    contribution_id = str(uuid.uuid4())[:12]
    csv_save_path = TRAINING_DATA_DIR / f"{contribution_id}.csv"
    csv_file.save(str(csv_save_path))

    df, error = validate_and_sanitize_csv(str(csv_save_path))
    if error:
        os.remove(str(csv_save_path))
        return jsonify({'error': error}), 400

    images_dir = IMAGES_DIR / contribution_id
    images_dir.mkdir(parents=True, exist_ok=True)

    image_files = request.files.getlist('images')
    for img_file in image_files:
        if img_file and allowed_file(img_file.filename, ALLOWED_IMAGE_EXTENSIONS):
            filename = secure_filename(img_file.filename)
            img_file.save(str(images_dir / filename))

    df.to_csv(str(csv_save_path), index=False)
    unique_labels = df['label'].unique().tolist()
    log_contribution(contribution_id, contributor, description, len(df), unique_labels)

    X, y, class_names, contribution_ids = prepare_dataset_from_contributions()
    if X is None or len(X) < 10:
        return jsonify({
            'message': 'Data accepted but insufficient for training',
            'contribution_id': contribution_id,
            'total_samples': len(X) if X is not None else 0
        }), 202

    try:
        metrics = train_model(X, y, class_names, contribution_ids, epochs=epochs)
    except Exception as e:
        return jsonify({
            'message': 'Data accepted but training failed',
            'contribution_id': contribution_id,
            'error': str(e)
        }), 500

    return jsonify({
        'message': 'Data contributed and model retrained successfully',
        'contribution_id': contribution_id,
        'metrics': metrics,
        'class_names': class_names
    })


