def create_demo_data():
    """Create synthetic demo data for testing."""
    demo_id = "demo_data"
    csv_path = TRAINING_DATA_DIR / f"{demo_id}.csv"
    images_dir = IMAGES_DIR / demo_id
    images_dir.mkdir(parents=True, exist_ok=True)

    if csv_path.exists():
        return

    records = []
    classes = {'red_square': (255, 0, 0), 'green_circle': (0, 255, 0), 'blue_triangle': (0, 0, 255)}

    for label, color in classes.items():
        for i in range(50):
            img = Image.new('RGB', IMG_SIZE, color=(0, 0, 0))
            pixels = img.load()

            noise_r = np.random.randint(-30, 30)
            noise_g = np.random.randint(-30, 30)
            noise_b = np.random.randint(-30, 30)

            for x in range(IMG_SIZE[0]):
                for y in range(IMG_SIZE[1]):
                    r = max(0, min(255, color[0] + noise_r + np.random.randint(-10, 10)))
                    g = max(0, min(255, color[1] + noise_g + np.random.randint(-10, 10)))
                    b = max(0, min(255, color[2] + noise_b + np.random.randint(-10, 10)))
                    pixels[x, y] = (r, g, b)

            filename = f"{label}_{i}.png"
            img.save(str(images_dir / filename))
            records.append({'image_path': filename, 'label': label})

    df = pd.DataFrame(records)
    df.to_csv(str(csv_path), index=False)

    log_contribution(demo_id, 'system', 'Demo synthetic data', len(records),
                     list(classes.keys()))

    logger.info("Demo data created: %d samples", len(records))


